    var currentPrice: Decimal
    var previousClose: Decimal
    var change: Decimal
    var changePercent: Decimal
    var volume: Int64
    var marketCap: Decimal?
    
    var isPositive: Bool {
        return change >= 0
    }
}

struct Trade: Codable, Identifiable {
    let id: String
    let symbol: String
    let type: TradeType
    let quantity: Int
    let price: Decimal
    let timestamp: Date
    let status: TradeStatus
    let totalAmount: Decimal
    
    enum TradeType: String, Codable {
        case buy
        case sell
    }
    
    enum TradeStatus: String, Codable {
        case pending
        case executed
        case failed
        case cancelled
    }
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    var quantity: Int
    var averagePrice: Decimal
    var currentPrice: Decimal
    var totalValue: Decimal {
        return currentPrice * Decimal(quantity)
    }
    var totalCost: Decimal {
        return averagePrice * Decimal(quantity)
    }
    var profitLoss: Decimal {
        return totalValue - totalCost
    }
    var profitLossPercent: Decimal {
        guard totalCost > 0 else { return 0 }
        return (profitLoss / totalCost) * 100
    }
}

struct Portfolio: Codable {
    var positions: [Position]
    var cashBalance: Decimal
    var totalValue: Decimal {
        let positionsValue = positions.reduce(Decimal(0)) { $0 + $1.totalValue }
        return positionsValue + cashBalance
    }
    var totalProfitLoss: Decimal {
        return positions.reduce(Decimal(0)) { $0 + $1.profitLoss }
    }
}

