class TradingService: ObservableObject {
    static let shared = TradingService()
    
    @Published var portfolio: Portfolio?
    @Published var recentTrades: [Trade] = []
    @Published var watchlist: [Stock] = []
    @Published var isLoading = false
    @Published var error: Error?
    
    private let apiManager = SecureAPIManager.shared
    private var cancellables = Set<AnyCancellable>()
    private var priceUpdateTimer: Timer?
    
    private init() {
        apiManager.loadAuthToken()
        startPriceUpdates()
    }
    
    func login(email: String, password: String) async throws {
        isLoading = true
        defer { isLoading = false }
        
        let credentials = ["email": email, "password": password]
        let response: APIResponse<[String: String]> = try await apiManager.request(
            endpoint: "/auth/login",
            method: "POST",
            body: credentials
        )
        
        guard response.success, let token = response.data?["token"] else {
            throw APIError.unauthorized
        }
        
        apiManager.setAuthToken(token)
        try await loadPortfolio()
    }
    
    func loadPortfolio() async throws {
        isLoading = true
        defer { isLoading = false }
        
        let response: APIResponse<User> = try await apiManager.request(endpoint: "/portfolio")
        
        guard response.success, let user = response.data else {
            throw APIError.invalidResponse
        }
        
        await MainActor.run {
            self.portfolio = user.portfolio
        }
    }
    
    func executeTrade(symbol: String, type: Trade.TradeType, quantity: Int, price: Decimal) async throws -> Trade {
        isLoading = true
        defer { isLoading = false }
        
        let request = TradeRequest(
            symbol: symbol,
            type: type.rawValue,
            quantity: quantity,
            price: price
        )
        
        let response: APIResponse<Trade> = try await apiManager.request(
            endpoint: "/trades/execute",
            method: "POST",
            body: request
        )
        
        guard response.success, let trade = response.data else {
            throw APIError.invalidResponse
        }
        
        await MainActor.run {
            self.recentTrades.insert(trade, at: 0)
        }
        
        try await loadPortfolio()
        
        return trade
    }
    
    func getStockQuote(symbol: String) async throws -> Stock {
        let response: APIResponse<Stock> = try await apiManager.request(endpoint: "/quotes/\(symbol)")
        
        guard response.success, let stock = response.data else {
            throw APIError.invalidResponse
        }
        
        return stock
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        let response: APIResponse<[Stock]> = try await apiManager.request(
            endpoint: "/stocks/search?q=\(query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? "")"
        )
        
        guard response.success, let stocks = response.data else {
            throw APIError.invalidResponse
        }
        
        return stocks
    }
    
    func addToWatchlist(stock: Stock) async throws {
        let response: APIResponse<Stock> = try await apiManager.request(
            endpoint: "/watchlist",
            method: "POST",
            body: ["symbol": stock.symbol]
        )
        
        guard response.success else {
            throw APIError.invalidResponse
        }
        
        await MainActor.run {
            if !self.watchlist.contains(where: { $0.symbol == stock.symbol }) {
                self.watchlist.append(stock)
            }
        }
    }
    
    func removeFromWatchlist(symbol: String) async throws {
        let response: APIResponse<[String: String]> = try await apiManager.request(
            endpoint: "/watchlist/\(symbol)",
            method: "DELETE"
        )
        
        guard response.success else {
            throw APIError.invalidResponse
        }
        
        await MainActor.run {
            self.watchlist.removeAll { $0.symbol == symbol }
        }
    }
    
    func loadTradeHistory() async throws {
        let response: APIResponse<[Trade]> = try await apiManager.request(endpoint: "/trades/history")
        
        guard response.success, let trades = response.data else {
            throw APIError.invalidResponse
        }
        
        await MainActor.run {
            self.recentTrades = trades
        }
    }
    
    private func startPriceUpdates() {
        priceUpdateTimer = Timer.scheduledTimer(withTimeInterval: 5.0, repeats: true) { [weak self] _ in
            Task {
                await self?.updatePrices()
            }
        }
    }
    
    private func updatePrices() async {
        guard !watchlist.isEmpty else { return }
        
        do {
            let symbols = watchlist.map { $0.symbol }.joined(separator: ",")
            let response: APIResponse<[Stock]> = try await apiManager.request(
                endpoint: "/quotes/batch?symbols=\(symbols)"
            )
            
            guard response.success, let stocks = response.data else { return }
            
            await MainActor.run {
                for stock in stocks {
                    if let index = self.watchlist.firstIndex(where: { $0.symbol == stock.symbol }) {
                        self.watchlist[index] = stock
                    }
                }
                
                if var portfolio = self.portfolio {
                    for stock in stocks {
                        if let index = portfolio.positions.firstIndex(where: { $0.symbol == stock.symbol }) {
                            portfolio.positions[index].currentPrice = stock.currentPrice
                        }
                    }
                    self.portfolio = portfolio
                }
            }
        } catch {
            print("Failed to update prices: \(error)")
        }
    }
}

